css:
@page {
    size: 80mm auto;
    margin: 4mm;
}

body{
    font-family: "Courier New", monospace;
    font-size:12px;
    color:#000;
}

.container{
    width:72mm;
}

/* Header */

.header{
    text-align:center;
    margin-bottom:6px;
}

.shop-name{
    font-size:16px;
    font-weight:bold;
}

.subtitle{
    font-size:11px;
}

/* Lines */

.line{
    border-top:1px dashed #000;
    margin:6px 0;
}

/* Rows */

.row{
    display:flex;
    justify-content:space-between;
    margin:3px 0;
}

/* Label */

.label{
    font-weight:bold;
}

/* Total Box */

.total-box{
    border-top:2px solid #000;
    border-bottom:2px solid #000;
    padding:6px 0;
    margin-top:6px;
}

.total{
    font-size:15px;
    font-weight:bold;
}

/* Footer */

.footer{
    text-align:center;
    font-size:11px;
    margin-top:6px;
}

/* Optional QR */

.qr{
    text-align:center;
    margin-top:8px;
}
